import{_ as a,H as t,f as i,i as l}from"./chunks/framework.DLd0CbzH.js";const u=JSON.parse('{"title":"Agent 基础","description":"","frontmatter":{},"headers":[],"relativePath":"fe/ai/agent/concept/index.md","filePath":"fe/ai/agent/concept/index.md","lastUpdated":1778229369000}'),n={name:"fe/ai/agent/concept/index.md"};function o(s,e,r,c,d,p){return t(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="agent-基础" tabindex="-1">Agent 基础 <a class="header-anchor" href="#agent-基础" aria-label="Permalink to &quot;Agent 基础&quot;">​</a></h1><h2 id="chatbot" tabindex="-1">Chatbot <a class="header-anchor" href="#chatbot" aria-label="Permalink to &quot;Chatbot&quot;">​</a></h2><p>只能一问一答的聊天机器人，比如初版 ChatGPT。</p><p>缺点：</p><ul><li>问一句回一句，需要追问、引导、复制粘贴结果</li><li>知识依赖训练数据，时效性差</li><li>无法连接外部系统，能力受限</li></ul><h2 id="agent" tabindex="-1">Agent <a class="header-anchor" href="#agent" aria-label="Permalink to &quot;Agent&quot;">​</a></h2><p>自主完成任务的 AI 系统，支持多轮思考、行动、观察，能调用外部工具、关键节点会停下来人工确认。</p><p>工作流程：给定目标、工具箱、边界 (预算/权限/审批/沙箱)，在循环中推进任务，直到完成或停下。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent = LLM + Tools + Memory + Harness</span></span></code></pre></div><ul><li><code>LLM</code>：输入提示词，思考后输出回答</li><li><code>Tools</code>：工具集合，包括内置工具、MCP 工具、Skill 系统、Hook 系统</li><li><code>Memory</code>：上下文与记忆，包括当前会话上下文 (context) 与持久化/跨会话记忆 (memory)</li><li><code>Harness</code>：外部约束，预算、权限、审批、沙箱、审计等</li></ul><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><p>适合 Agent 执行的任务：</p><ul><li>目标明确，有清晰的完成标准</li><li>步骤可拆解，可分解为子任务</li><li>结果可验证，能判断是否完成</li><li>信息可获取，能通过工具获取需要的信息</li><li>重复性高，有自动化价值</li></ul><p>不适合 Agent 的任务：</p><ul><li>开放性问题，没有明确完成标准</li><li>主观判断，依赖人类审美和价值观</li><li>高风险决策，需要有人负责</li><li>不可逆副作用，需要人类确认、担责</li></ul><p>简单判断：任务交给一个实习生、能用文字清楚描述怎么做，大概率适合 Agent。</p>',16)])])}const g=a(n,[["render",o]]);export{u as __pageData,g as default};
